---
/**
 * @component RadioGroup
 * @title Radio Group
 * @description A group of options where users can select exactly one choice.
 * @figmaUrl https://www.figma.com/design/koxai7zw5vIuBzuVxe5T2l/bejamas-ui?node-id=2549-18817&t=YFStJ3V8fXEO8QD8-4
 *
 * @preview
 *
 * <RadioGroup name="plan" defaultValue="free">
 *   <div class="flex items-center gap-2">
 *     <RadioGroupItem value="free" id="free" />
 *     <Label for="free">Free</Label>
 *   </div>
 *   <div class="flex items-center gap-2">
 *     <RadioGroupItem value="pro" id="pro" />
 *     <Label for="pro">Pro</Label>
 *   </div>
 * </RadioGroup>
 *
 * @usage
 *
 * ```astro nocollapse
 * ---
 * import { RadioGroup, RadioGroupItem } from '@bejamas/ui/components/radio-group';
 * import { Label } from '@bejamas/ui/components/label';
 * ---
 *
 * <RadioGroup name="plan" defaultValue="free">
 *   <div class="flex items-center gap-2">
 *     <RadioGroupItem value="free" id="free" />
 *     <Label for="free">Free</Label>
 *   </div>
 * </RadioGroup>
 * ```
 */
import type { HTMLAttributes } from "astro/types";
import { cn } from "@/lib/utils";

interface Props extends HTMLAttributes<"div"> {
  class?: string;
  defaultValue?: string;
  name?: string;
  disabled?: boolean;
  readOnly?: boolean;
  required?: boolean;
  "aria-label"?: string;
  "aria-labelledby"?: string;
}

const {
  class: className = "",
  defaultValue,
  name,
  disabled = false,
  readOnly = false,
  required = false,
  ...rest
} = Astro.props as Props;
---

<div
  {...rest}
  data-slot="radio-group"
  data-default-value={defaultValue}
  data-name={name}
  data-disabled={disabled ? "true" : undefined}
  data-read-only={readOnly ? "true" : undefined}
  data-required={required ? "true" : undefined}
  class={cn("grid gap-2", className)}
>
  <slot />
</div>

<script>
  import { createRadioGroup } from "@data-slot/radio-group";

  document
    .querySelectorAll('[data-slot="radio-group"]')
    .forEach((el) => createRadioGroup(el));
</script>

---
import { cn } from "@/lib/utils";
import type { HTMLAttributes } from "astro/types";

interface Props extends HTMLAttributes<"span"> {
  value: string;
  class?: string;
  disabled?: boolean;
  id?: string;
  "aria-invalid"?: boolean | "true" | "false";
}

const {
  class: className = "",
  id = "",
  value,
  disabled = false,
  "aria-invalid": ariaInvalid,
  ...rest
} = Astro.props as Props;
---

<span
  {...rest}
  id={id}
  data-slot="radio-group-item"
  data-value={value}
  data-disabled={disabled ? "true" : undefined}
  aria-invalid={ariaInvalid}
  class={cn(
    "border-input dark:bg-input/30 data-checked:bg-primary data-checked:text-primary-foreground dark:data-checked:bg-primary data-checked:border-primary aria-invalid:aria-checked:border-primary aria-invalid:border-destructive focus-visible:border-ring focus-visible:ring-ring/50 aria-invalid:ring-destructive/20 dark:aria-invalid:ring-destructive/40 dark:aria-invalid:border-destructive/50 flex size-4 rounded-full focus-visible:ring-3 aria-invalid:ring-3 group/radio-group-item peer relative aspect-square shrink-0 border outline-none after:absolute after:-inset-x-3 after:-inset-y-2 disabled:cursor-not-allowed disabled:opacity-50",
    className,
  )}
>
  <span
    aria-hidden="true"
    data-slot="radio-group-indicator"
    class="flex size-4 items-center justify-center data-unchecked:hidden"
  >
    <span class="bg-primary-foreground absolute top-1/2 left-1/2 size-2 -translate-x-1/2 -translate-y-1/2 rounded-full"></span>
  </span>
</span>
